            <h4><ChevronRight size={14} /> Pauta para Próxima Sessão</h4>
            <ul>
              {sections.sessao.split('\n').map((line, i) => line.trim() && (
                <li key={i}>{line.replace(/^[-*]\s*/, '')}</li>
              ))}
            </ul>
          </div>
        )}
      </div>
    );
  };

  const copiarParaPsicologo = () => {
    if (!exercicio) return;

    const getMatch = (tag) => {
      const regex = new RegExp(`${tag}:([\\s\\S]*?)(?=[A-Z]{4,}:|$)`);
      const match = exercicio.match(regex);
      return match ? match[1].trim() : null;
    };

    const laudo = getMatch('LAUDO');
    const mapa = getMatch('MAPA');
    const pauta = getMatch('SESSAO');

    const resumo = `
RESUMO CLÍNICO - PSICÓLOGO IA
==============================
DATA: ${sessaoAtiva?.data || new Date().toLocaleString()}

1. MEU DESABAFO:
"${transcricao}"

2. LAUDO DE ACOMPANHAMENTO:
${laudo}

3. MAPA DE SENSIBILIDADE (GATILHOS):
${mapa}

4. PAUTA PARA A PRÓXIMA SESSÃO:
${pauta}

------------------------------
Gerado por Psicólogo IA
    `;
    navigator.clipboard.writeText(resumo);
    alert("Resumo clínico copiado para transferência!");
  };

  // Subview: Agenda e Agendamento (Fase 3)
  const AgendaView = () => {
