              {dataSelecionada && (
                <div className="form-group">
                  <label>Selecione o Horário</label>
                  {horariosDisponiveis.length === 0 ? (
                    <p style={{ fontSize: '0.85rem', color: 'var(--text-muted)', marginTop: '4px' }}>
