                {carregando ? 'Agendando...' : 'Confirmar Consulta'}
              </button>
            </form>
          </div>
        )}

        <div className="agenda-list-side" style={{ flex: usuario.tipo === 'psicologo' ? 1 : 1.2 }}>
          <h3 style={{ fontFamily: 'Outfit, sans-serif', fontSize: '1.4rem', marginBottom: '1rem' }}>
            {usuario.tipo === 'paciente' ? 'Suas Consultas' : 'Agenda do Paciente'}
          </h3>

          <div style={{ display: 'flex', flexDirection: 'column', gap: '12px', maxHeight: '550px', overflowY: 'auto' }}>
            {listaConsultas.map((c) => (
