                <div className="appointment-info">
                  <span className="appointment-date">{c.data_hora}</span>
                  <span className="appointment-meta">
                    {usuario.tipo === 'paciente' ? `Psicólogo: Dr(a). ${c.psicologo_nome}` : `Paciente: ${c.paciente_nome}`}
