                <Calendar size={32} style={{ color: 'var(--accent)', opacity: 0.4, marginBottom: '0.75rem' }} />
                <p style={{ color: 'var(--text-muted)', fontSize: '0.9rem' }}>Nenhuma consulta agendada.</p>
