          {usuario.tipo === 'paciente' && (
            <div className="finance-form-side">
              <h3 style={{ fontFamily: 'Outfit, sans-serif', fontSize: '1.3rem', marginBottom: '1.25rem' }}>Seus Saldos de Sessões</h3>
              {listaPacotes.map((p) => (
                <div key={p.id} className="pacote-card" style={{ marginBottom: '12px' }}>
                  <div className="pacote-info">
                    <span className="pacote-title">Pacote Contratado ({p.data_criacao})</span>
                    <span style={{ fontSize: '0.8rem', color: 'var(--text-muted)' }}>Status: {p.status === 'ativo' ? 'Ativo' : 'Concluído'}</span>
                  </div>
                  <div className="pacote-saldos">
                    {p.sessoes_restantes} / {p.total_sessoes}
                  </div>
                </div>
              ))}
              {listaPacotes.length === 0 && (
                <p style={{ color: 'var(--text-muted)', fontSize: '0.85rem' }}>Você não possui pacotes ativos. Suas sessões serão cobradas de forma avulsa.</p>
              )}
