          <div className="finance-list-side">
            <h3 style={{ fontFamily: 'Outfit, sans-serif', fontSize: '1.3rem', marginBottom: '1rem' }}>
              {usuario.tipo === 'paciente' ? 'Seu Histórico de Cobranças' : pacienteSelecionado ? 'Mensalidades e Sessões do Paciente' : 'Livro de Lançamentos'}
